+        let vs2 = VecStorage::new(make_cells("cd"));
+        assert_ne!(vs1, vs2);
+    }
+
+    #[test]
+    fn vec_storage_debug() {
+        let vs = VecStorage::new(make_cells("x"));
+        let dbg = format!("{:?}", vs);
